#include <stdio.h>
#include <string.h>
#define MAXN 1000
int main() {
    int N, M;
    char s[MAXN + 1];
    scanf("%d %d", &N, &M);
    scanf("%s", s);
    for (int i = 0; i < M; i++) {
        int type, L, R;
        scanf("%d %d %d", &type, &L, &R);
        if (type == 1) {
            // Reverse the substring from L to R
            int left = L - 1;
            int right = R - 1;
            while (left < right) {
                char temp = s[left];
                s[left] = s[right];
                s[right] = temp;
                left++;
                right--;
            }
        } else if (type == 2) {
            // Calculate the number of distinct palindromes
            int freq[26] = {0};
            for (int j = L - 1; j <= R - 1; j++) {
                freq[s[j] - 'a']++;
            }
            long long perm = 1;
            for (int j = 0; j < 26; j++) {
                if (freq[j] > 0) {
                    perm *= freq[j];
                }
            }
            printf("%lld\n", perm);
        }
    }
    return 0;
}

