import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int M = sc.nextInt();
        String s = sc.next();
        for (int i = 0; i < M; i++) {
            int type = sc.nextInt();
            int L = sc.nextInt();
            int R = sc.nextInt();
            if (type == 1) {
                // Reverse the substring from L to R
                StringBuilder sb = new StringBuilder(s);
                int left = L - 1;
                int right = R - 1;
                while (left < right) {
                    char temp = sb.charAt(left);
                    sb.setCharAt(left, sb.charAt(right));
                    sb.setCharAt(right, temp);
                    left++;
                    right--;
                }
                s = sb.toString();
            } else if (type == 2) {
                // Calculate the number of distinct palindromes
                int freq[] = new int[26];
                for (int j = L - 1; j <= R - 1; j++) {
                    freq[s.charAt(j) - 'a']++;
                }
                long perm = 1;
                for (int j = 0; j < 26; j++) {
                    if (freq[j] > 0) {
                        perm *= freq[j];
                    }
                }
                System.out.println(perm);
            }
        }
    }
}

