const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const N = parseInt(readline().split(' ')[0]);
const M = parseInt(readline().split(' ')[1]);
const s = readline().trim();
for (let i = 0; i < M; i++) {
    const [type, L, R] = readline().split(' ').map(Number);
    if (type === 1) {
        // Reverse the substring from L to R
        const left = L - 1;
        const right = R - 1;
        const arr = s.split('');
        while (left < right) {
            const temp = arr[left];
            arr[left] = arr[right];
            arr[right] = temp;
            left++;
            right--;
        }
        s = arr.join('');
    } else if (type === 2) {
        // Calculate the number of distinct palindromes
        const freq = new Array(26).fill(0);
        for (let j = L - 1; j <= R - 1; j++) {
            freq[s.charCodeAt(j) - 'a'.charCodeAt(0)]++;
        }
        let perm = 1;
        for (let j = 0; j < 26; j++) {
            if (freq[j] > 0) {
                perm *= freq[j];
            }
        }
        console.log(perm);
    }
}
